1	//! `--scope` — which side(s) of a dual workspace a command
2	//! operates on. See [options_flags](README.md) for shared
3	//! architecture.
4	//!
5	//! - `Side` is the role enum — `Work` or `Bot`; the CLI
6	//!   keywords that name them are `work` and `bot`.
7	//! - `Scope` is a newtype over `Vec<Side>` — the parsed role
8	//!   set (`work`, `bot`, `work,bot`, `bot,work`).
9	//! - Path-based single-repo operation lives on `-R/--repo`,
10	//!   not in `--scope`; `Scope` carries role information only.
11	
12	use clap::ValueEnum;
13	
14	/// One side of a dual-repo workspace.
15	///
16	/// - `Work` — the primary work repo.
17	/// - `Bot` — the bot repo (typically at `.claude/`).
18	#[derive(Copy, Clone, Debug, PartialEq, Eq, ValueEnum)]
19	pub enum Side {
20	    Work,
21	    Bot,
22	}
23	
24	/// Parsed `--scope` value — the requested role set of a
25	/// dual-repo workspace.
26	///
27	/// Newtype over `Vec<Side>`; the vector preserves the order the
28	/// keywords were given in (`work,bot` vs `bot,work`).
29	#[derive(Clone, Debug, PartialEq, Eq)]
30	pub struct Scope(pub Vec<Side>);
31	
32	/// Parse a `--scope` value string.
33	///
34	/// Accepts exactly the four role-keyword forms — `work`, `bot`,
35	/// `work,bot`, `bot,work` — preserving order. Anything else (an
36	/// empty string, a bare name, duplicate or out-of-set
37	/// combinations, a path) is an error: path-based single-repo
38	/// operation uses `-R/--repo`, not `--scope`.
39	pub fn parse_scope(s: &str) -> Result<Scope, String> {
40	    match s {
41	        "work" => Ok(Scope(vec![Side::Work])),
42	        "bot" => Ok(Scope(vec![Side::Bot])),
43	        "work,bot" => Ok(Scope(vec![Side::Work, Side::Bot])),
44	        "bot,work" => Ok(Scope(vec![Side::Bot, Side::Work])),
45	        "" => Err("--scope: value is empty".into()),
46	        other => Err(format!(
47	            "--scope: '{other}' is not a recognized form. \
48	             Expected one of `work`, `bot`, `work,bot`, `bot,work`. \
49	             For single-repo operation by path, use `-R/--repo`."
50	        )),
51	    }
52	}
53	
54	impl Scope {
55	    /// True when the role set includes the work side.
56	    pub fn has_work(&self) -> bool {
57	        self.0.contains(&Side::Work)
58	    }
59	
60	    /// True when the role set includes the bot side.
61	    pub fn has_bot(&self) -> bool {
62	        self.0.contains(&Side::Bot)
63	    }
64	
65	    /// Exactly the work side — a single-side dual-repo op.
66	    pub fn is_work_only(&self) -> bool {
67	        self.has_work() && !self.has_bot()
68	    }
69	
70	    /// Exactly the bot side — a single-side dual-repo op.
71	    #[allow(dead_code)]
72	    pub fn is_bot_only(&self) -> bool {
73	        !self.has_work() && self.has_bot()
74	    }
75	
76	    /// Both sides — a full dual-repo op.
77	    pub fn is_both(&self) -> bool {
78	        self.has_work() && self.has_bot()
79	    }
80	}
81	
82	#[cfg(test)]
83	mod tests {
84	    use super::*;
85	
86	    #[test]
87	    fn work_only() {
88	        let s = Scope(vec![Side::Work]);
89	        assert!(s.is_work_only());
90	        assert!(!s.is_bot_only());
91	        assert!(!s.is_both());
92	    }
93	
94	    #[test]
95	    fn bot_only() {
96	        let s = Scope(vec![Side::Bot]);
97	        assert!(!s.is_work_only());
98	        assert!(s.is_bot_only());
99	        assert!(!s.is_both());
100	    }
101	
102	    #[test]
103	    fn both_work_then_bot() {
104	        let s = Scope(vec![Side::Work, Side::Bot]);
105	        assert!(!s.is_work_only());
106	        assert!(!s.is_bot_only());
107	        assert!(s.is_both());
108	    }
109	
110	    #[test]
111	    fn both_bot_then_work() {
112	        // Order doesn't matter — contains-based checks.
113	        let s = Scope(vec![Side::Bot, Side::Work]);
114	        assert!(s.is_both());
115	    }
116	
117	    #[test]
118	    fn empty_roles() {
