//! `--dry-run` — show what would be done without executing.
//! See [options_flags](README.md) for shared architecture.

use clap::Args;

/// `--dry-run` leaf (Flag — boolean domain) — see
/// [Consuming an OF](README.md#consuming-an-of).
#[derive(Args, Debug, Clone, Default)]
pub struct DryRunFlag {
    /// Dry run — show what would be done without executing.
    #[arg(long)]
    pub dry_run: bool,
}
//! `--private` — create private repos on the remote provisioner.
//! See [options_flags](README.md) for shared architecture.

use clap::Args;

/// `--private` leaf (Flag — boolean domain) — see
/// [Consuming an OF](README.md#consuming-an-of).
#[derive(Args, Debug, Clone, Default)]
pub struct PrivateFlag {
    /// Create private GitHub repos (default: public).
    ///
    /// - Only meaningful when the resolved provisioner is
    ///   `gh repo create` (GitHub URL or `--repo remote` whose
    ///   value points at GitHub).
    #[arg(long, verbatim_doc_comment)]
    pub private: bool,
}
//! `--account` — selects an account section in the user config.
//! See [options_flags](README.md) for shared architecture.

use clap::Args;

/// `--account` leaf (Option — non-boolean domain) — see
/// [Consuming an OF](README.md#consuming-an-of).
#[derive(Args, Debug, Clone, Default)]
pub struct AccountOption {
    /// Account name — picks `[account.<a>]` from user config.
    ///
    /// - Without this flag, `[default].account` (or top-level
    ///   `[repo]` shorthand) is used.
    /// - Meaningful only with Path or bare-NAME targets — URL /
    ///   owner/name targets supply the remote directly.
    #[arg(long, value_name = "NAME", verbatim_doc_comment)]
    pub account: Option<String>,
}
//! `--config none|<path>` — `.vc-config.toml` write override.
//! See [options_flags](README.md) for shared architecture.

use std::path::PathBuf;

use clap::Args;

/// Parsed `--config` value.
#[derive(Clone, Debug, PartialEq, Eq)]
pub enum ConfigKind {
    /// Skip writing entirely (`--config none`).
    None,
    /// User-provided file (`--config <path>`).
    Path(PathBuf),
}

/// Parse `--config`; `""` returns `default`, `"none"` returns
/// `ConfigKind::None`, anything else is a path.
pub fn parse_config_kind(s: &str, default: ConfigKind) -> ConfigKind {
    match s {
        "" => default,
        "none" => ConfigKind::None,
        _ => ConfigKind::Path(PathBuf::from(s)),
    }
}

/// `--config none|<path>` leaf (Option — non-boolean domain) —
/// see [Consuming an OF](README.md#consuming-an-of).
#[derive(Args, Debug, Clone, Default)]
pub struct ConfigOption {
    /// Override the canned `.vc-config.toml` write.
    ///
    /// - Absent: write the canned `.vc-config.toml`.
    /// - `--config none`: skip writing entirely.
    /// - `--config <path>`: copy `<path>` to `.vc-config.toml`
    ///   (bytewise; no schema validation).
    #[arg(long = "config", value_name = "none|PATH", verbatim_doc_comment)]
    pub raw: Option<String>,
}

impl ConfigOption {
    /// Resolve `raw` against `default`; `None` when flag absent.
    pub fn resolve(&self, default: ConfigKind) -> Option<ConfigKind> {
        self.raw.as_deref().map(|s| parse_config_kind(s, default))
    }

